local terminal = "alacritty"
local fileManager = "nemo"
local menu = "noctalia-shell ipc call launcher toggle"

--############
--## INPUT ###
--############

-- https://wiki.hyprland.org/Configuring/Variables/#input

local mainMod = "SUPER"

hl.bind(mainMod .. " + Q", hl.dsp.exec_cmd(terminal))
hl.bind(mainMod .. " + SHIFT + Q", hl.dsp.exec_cmd("cool-retro-term --fullscreen"))
hl.bind(mainMod .. " + TAB", hl.dsp.window.close())
hl.bind(mainMod .. " + M", hl.dsp.exit())
hl.bind(mainMod .. " + E", hl.dsp.exec_cmd(fileManager))
hl.bind(mainMod .. " + V", hl.dsp.window.float({ action = "toggle" }))
hl.bind(mainMod .. " + RETURN", hl.dsp.exec_cmd(menu))
hl.bind(mainMod .. " + P", hl.dsp.window.pseudo())
hl.bind(mainMod .. " + B", hl.dsp.exec_cmd("chromium"))
hl.bind(mainMod .. " + U", hl.dsp.exec_cmd("qimgv ~/Pictures/black.jpg"))
hl.bind(mainMod .. " + F", hl.dsp.window.fullscreen())
hl.bind(mainMod .. " + code:49", hl.dsp.exec_cmd("noctalia-shell ipc call controlCenter toggle"))

hl.bind("CTRL + SHIFT + ESCAPE", hl.dsp.exec_cmd("[float] alacritty -e btop"))

hl.bind(mainMod .. " + Z", hl.dsp.pass({ window = "class:^(com\\.obsproject\\.Studio)$" }))
