hl.bind(mainMod .. " + O", hl.dsp.exec_cmd("./Scripts/stream.sh"))

hl.bind(mainMod .. " + SHIFT + Print", hl.dsp.exec_cmd("grim -g \"$(slurp -d)\" \"$HOME/Pictures/Screenshots/$(date '+%y%m%d_%H-%M-%S').png\""))
hl.bind("Print", hl.dsp.exec_cmd("grim -o DP-1 \"$HOME/Pictures/Screenshots/$(date '+%y%m%d_%H-%M-%S').png\""))

hl.bind(mainMod .. " + left", hl.dsp.focus({ direction = "left" }))
